const statusIcons = {
  pending: Clock,
  confirmed: CheckCircle,
  preparing: Clock,
  ready: CheckCircle,
  delivering: Truck,
  delivered: CheckCircle,
  cancelled: XCircle
};

const OrdersPage = () => {
  const [orders, setOrders] = useState([]);
  const [filteredOrders, setFilteredOrders] = useState([]);
  const [activeFilter, setActiveFilter] = useState('all');
  const [loading, setLoading] = useState(true);

  const filters = [
    { key: 'all', label: 'All Orders' },
    { key: 'pending', label: 'Pending' },
    { key: 'confirmed', label: 'Confirmed' },
    { key: 'preparing', label: 'Preparing' },
    { key: 'ready', label: 'Ready' },
    { key: 'delivering', label: 'Delivering' },
    { key: 'delivered', label: 'Delivered' },
    { key: 'cancelled', label: 'Cancelled' }
  ];

  useEffect(() => {
    const loadOrders = async () => {
      try {
        setLoading(true);
        const response = await orderAPI.getUserOrders();

        if (response.success) {
          setOrders(response.data || []);
        } else {
          console.error('Failed to load orders:', response.message);
          setOrders([]);
        }
      } catch (error) {
        console.error('Error loading orders:', error);
        setOrders([]);
      } finally {
        setLoading(false);
      }
    };

    loadOrders();
  }, []);

  useEffect(() => {
    if (activeFilter === 'all') {
      setFilteredOrders(orders);
    } else {
      setFilteredOrders(orders.filter(order => order.status === activeFilter));
    }
  }, [activeFilter, orders]);

  const formatDate = (date) => {
    return new Intl.DateTimeFormat('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    }).format(date);
  };

  const StatusIcon = statusIcons[activeFilter] || Clock;

  if (loading) {
    return (
      <OrdersContainer>
        <LoadingMessage>Loading your orders...</LoadingMessage>
      </OrdersContainer>
    );
  }

  if (filteredOrders.length === 0) {
    return (
      <OrdersContainer>
        <OrdersHeader>
          <OrdersTitle>
            <ShoppingBag size={32} />
            My Orders
          </OrdersTitle>
          <p style={{ color: theme.colors.gray[600] }}>
            Track and manage your food orders
          </p>
        </OrdersHeader>

        <FilterTabs>
          {filters.map(filter => (
            <FilterTab
              key={filter.key}
              active={activeFilter === filter.key}
              onClick={() => setActiveFilter(filter.key)}
            >
              {filter.label}
            </FilterTab>
          ))}
        </FilterTabs>

        <EmptyOrders>
          <EmptyOrdersIcon>
            <ShoppingBag size={64} />
          </EmptyOrdersIcon>
          <EmptyOrdersTitle>No orders found</EmptyOrdersTitle>
          <EmptyOrdersMessage>
            {activeFilter === 'all' 
              ? "You haven't placed any orders yet. Start browsing our menu!"
              : `You don't have any ${activeFilter} orders.`
            }
          </EmptyOrdersMessage>
          <Button as={Link} to="/menu" size="lg">
            Browse Menu
          </Button>
        </EmptyOrders>
      </OrdersContainer>
    );
  }

  return (
    <OrdersContainer>
      <OrdersHeader>
        <OrdersTitle>
          <ShoppingBag size={32} />
          My Orders
        </OrdersTitle>
        <p style={{ color: theme.colors.gray[600] }}>
          Track and manage your food orders
        </p>
      </OrdersHeader>

      <FilterTabs>
        {filters.map(filter => (
          <FilterTab
            key={filter.key}
            active={activeFilter === filter.key}
            onClick={() => setActiveFilter(filter.key)}
          >
            {filter.label}
          </FilterTab>
        ))}
      </FilterTabs>

      <OrdersGrid>
        {filteredOrders.map(order => {
          const StatusIcon = statusIcons[order.status] || Clock;
          return (
            <OrderCard key={order.id}>
              <CardBody>
                <OrderHeader>
                  <OrderInfo>
                    <OrderNumber>Order #{order.id}</OrderNumber>
                    <OrderDate>
                      <Calendar size={16} />
                      {formatDate(order.date)}
                    </OrderDate>
                  </OrderInfo>
                  <OrderStatus status={order.status}>
                    <StatusIcon size={16} />
                    {order.status.charAt(0).toUpperCase() + order.status.slice(1)}
                  </OrderStatus>
                </OrderHeader>

                <OrderContent>
                  <OrderItems>
                    {order.items.map((item, index) => (
                      <OrderItem key={index}>
                        <ItemName>{item.name}</ItemName>
                        <ItemQuantity>x{item.quantity}</ItemQuantity>
                        <ItemPrice>${(item.price * item.quantity).toFixed(2)}</ItemPrice>
                      </OrderItem>
                    ))}
                  </OrderItems>

                  <OrderSummary>
                    <SummaryItem>
                      <span>Subtotal:</span>
                      <span>${order.subtotal.toFixed(2)}</span>
                    </SummaryItem>
                    <SummaryItem>
                      <span>Tax:</span>
                      <span>${order.tax.toFixed(2)}</span>
                    </SummaryItem>
                    <SummaryItem>
                      <span>Delivery:</span>
                      <span>{order.deliveryFee === 0 ? 'FREE' : `$${order.deliveryFee.toFixed(2)}`}</span>
                    </SummaryItem>
                    <SummaryTotal>
                      <span>Total:</span>
                      <span>${order.total.toFixed(2)}</span>
                    </SummaryTotal>
                  </OrderSummary>
                </OrderContent>

                <OrderActions>
                  <ViewOrderButton as={Link} to={`/orders/${order.id}`} variant="outline">
                    <Eye size={16} />
                    View Details
                  </ViewOrderButton>
                  {order.status === 'delivered' && (
                    <Button>
                      Order Again
                    </Button>
                  )}
                </OrderActions>
              </CardBody>
            </OrderCard>
          );
        })}
      </OrdersGrid>
    </OrdersContainer>
  );
};

export default OrdersPage;
